INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '651ccd13-ffe6-42fd-b029-dd01104d880c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Terraform's IaC Philosophy — Reproducibility, Drift, and Why State Is the Source of Truth$escape$,
  $escape$Terraform's power isn't just provisioning — it's the contract between your declared intent and reality. Every `terraform apply` is idempotent: run it 100 times on the same config, you get the same infrastructure. This reproducibility is enforced through the state file (`terraform.tfstate`), which maps your HCL resources to real cloud objects.

Drift happens when someone manually changes a resource outside Terraform. Run `terraform plan` and you'll see it immediately — Terraform diffs the live API state against your state file and flags divergences. This is your audit trail: every `terraform apply` is logged, every change is reviewable in `tfplan` output or remote state history (Terraform Cloud/HCP Terraform).

Auditability is baked in via `-out=tfplan` + `terraform show -json tfplan` — you can parse exactly what will change before it happens. Pair this with `required_providers` version locking in `terraform.lock.hcl` and your infra becomes fully reproducible across teams and environments. IaC matters because undocumented clickops is a liability; Terraform makes every infrastructure decision a reviewable, versionable, reversible commit.$escape$,
  $escape$# Detect drift without applying
terraform plan -detailed-exitcode
# Exit code 2 = drift detected

# Save and inspect a plan before applying
terraform plan -out=tfplan
terraform show -json tfplan | jq '.resource_changes[] | select(.change.actions != ["no-op"])'

# Lock provider versions for reproducibility
terraform providers lock \
  -platform=linux_amd64 \
  -platform=darwin_arm64$escape$,
  $escape$bash$escape$,
