INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b8f09a38-6222-43e2-9b80-cb119bafa559',
  '00000000-0000-0000-0000-000000000001',
  $escape$Terraform to AWS CDK — Understanding L1/L2/L3 Construct Abstractions$escape$,
  $escape$Coming from Terraform, AWS CDK's three-tier abstraction model maps cleanly to concepts you already know. L1 constructs (prefixed `Cfn*`) are raw CloudFormation resources — equivalent to writing `aws_cloudformation_stack` in Terraform with hand-rolled YAML. No defaults, full control, maximum verbosity. L2 constructs are CDK's answer to a well-written Terraform module: opinionated wrappers that handle IAM roles, security group rules, and encryption flags automatically. `s3.Bucket` instead of `CfnBucket` — same resource, drastically fewer lines. L3 constructs (the `aws-solutions-constructs` library) bundle multiple L2s into repeatable patterns, like a curated Terraform registry module — `aws-apigateway-lambda` wires API Gateway + Lambda + CloudWatch in ~10 lines. CDK Stacks are the unit of deployment, analogous to a Terraform workspace: each stack synthesizes to a CloudFormation template with isolated state. Cross-stack references use `stack.exportValue()`, mirroring Terraform's `output` + `terraform_remote_state` pattern. The critical shift: CDK state lives in CloudFormation, not an S3 backend `.tfstate` file — `cdk deploy` is your `terraform apply`.$escape$,
  $escape$import * as s3 from 'aws-cdk-lib/aws-s3';

// L1 — raw CloudFormation (like hand-writing aws_cloudformation_stack in Terraform)
const l1Bucket = new s3.CfnBucket(this, 'L1Bucket', {
  bucketEncryption: {
    serverSideEncryptionConfiguration: [{
      serverSideEncryptionByDefault: { sseAlgorithm: 'AES256' }
    }]
  }
});

// L2 — opinionated defaults (like a well-written Terraform module)
const l2Bucket = new s3.Bucket(this, 'L2Bucket', {
  encryption: s3.BucketEncryption.S3_MANAGED,
  blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL,
  versioned: true
});$escape$,
