INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ef1ef305-45c7-4d18-9486-2717e30c5f17',
  '00000000-0000-0000-0000-000000000001',
  $escape$Terraform Testing Stack — terratest, checkov, tfsec, and OPA in Practice$escape$,
  $escape$Most Terraform bugs surface in production because engineers skip the testing layer entirely. A solid IaC pipeline has three distinct gates.

**Static analysis** runs first — `checkov` scans your `.tf` files for misconfigurations (e.g. S3 buckets with public ACLs, security groups with `0.0.0.0/0` ingress) before `terraform plan` even runs. `tfsec` overlaps but focuses on CVE-mapped security rules and emits SARIF output for GitHub Code Scanning.

**Policy as code** sits at the plan stage. Feed `terraform show -json tfplan.binary` into OPA's `conftest` to enforce org-wide rules — mandatory tags, approved AMI IDs, restricted instance types — without polluting modules with one-off `validation` blocks.

**Integration testing** with `terratest` spins up real infrastructure in an isolated AWS account, runs Go assertions against live resource attributes (`terraform.Output`, `aws.GetS3BucketPolicy`), then destroys everything with `defer terraform.Destroy()`. Gate this behind a nightly CI workflow — it's slow but catches drift that static tools miss entirely.$escape$,
  $escape$package test

import (
	"testing"
	"github.com/gruntwork-io/terratest/modules/terraform"
	"github.com/stretchr/testify/assert"
)

func TestS3BucketIsPrivate(t *testing.T) {
	opts := &terraform.Options{
		TerraformDir: "../modules/s3",
		Vars: map[string]interface{}{"bucket_name": "test-byteai-bucket"},
	}
	defer terraform.Destroy(t, opts)
	terraform.InitAndApply(t, opts)
	acl := terraform.Output(t, opts, "bucket_acl")
	assert.Equal(t, "private", acl)
}$escape$,
  $escape$go$escape$,
