INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '04f6995a-b0dc-42fa-9ae4-9f893c6d38f5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Terraform import — Bringing Existing Infrastructure Under IaC Control$escape$,
  $escape$Before Terraform 1.5, importing existing resources meant running `terraform import <address> <id>` to populate state, then manually writing the matching HCL — a tedious, error-prone process. Terraform 1.5+ introduces `import` blocks, letting you declare imports as code and use `terraform plan -generate-config-out=generated.tf` to auto-generate the HCL skeleton.

Declare an `import` block with the target resource address and its provider-specific ID. On `terraform plan`, Terraform reads the live resource and emits a `.tf` file with all attributes populated. Review and clean up the generated config — remove computed fields Terraform manages automatically — then run `terraform apply` to finalize state.

For bulk imports, pair `import` blocks with `for_each`. Define a local map of IDs, reference it in both the `import` block and the resource block, and Terraform handles the entire batch in one apply. After import, always run `terraform plan` to confirm zero drift between your config and actual state before treating the resource as fully managed.$escape$,
  $escape$# terraform >= 1.5 — import block approach
locals {
  buckets = {
    assets = "my-assets-bucket-prod"
    logs   = "my-logs-bucket-prod"
  }
}

import {
  for_each = local.buckets
  to       = aws_s3_bucket.this[each.key]
  id       = each.value
}

resource "aws_s3_bucket" "this" {
  for_each = local.buckets
  bucket   = each.value
}$escape$,
  $escape$bash$escape$,
