INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e7b3f627-8860-45d7-bcd7-3e764da68a4d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Terraform CI/CD — Automated plan on PR, apply on merge, drift alerts$escape$,
  $escape$A robust Terraform CI/CD pipeline has three distinct gates. On pull request, run `terraform plan` and post the output as a PR comment using `github-script` — never merge blind. Use `-detailed-exitcode` to fail the check if there are pending changes, keeping plan output machine-readable. On merge to main, run `terraform apply -auto-approve` only after a successful plan artifact from the same commit SHA, preventing plan/apply drift between pipeline runs. Store state in a remote backend (S3 + DynamoDB or Terraform Cloud) with state locking so concurrent applies are blocked at the backend level, not just the CI layer.

For drift detection, schedule a nightly `terraform plan -detailed-exitcode` job. Exit code `2` means real drift — pipe this into a Slack webhook or PagerDuty alert. Pair with `TF_CLI_ARGS_plan=-lock=false` so the scheduled read-only check never blocks active applies. Use workspaces or separate state files per environment to scope drift alerts precisely — you want "prod drifted", not "something drifted somewhere".$escape$,
  $escape$# .github/workflows/terraform.yml (abbreviated)
jobs:
  plan:
    if: github.event_name == 'pull_request'
    steps:
      - run: terraform plan -detailed-exitcode -out=tfplan 2>&1 | tee plan.txt
      - uses: actions/github-script@v7
        with:
          script: |
            const plan = require('fs').readFileSync('plan.txt', 'utf8')
            github.rest.issues.createComment({ ...context.repo, issue_number: context.issue.number, body: '```\n' + plan + '\n```' })

  apply:
    if: github.ref == 'refs/heads/main' && github.event_name == 'push'
    steps:
      - run: terraform apply -auto-approve tfplan

  drift:
    if: github.event_name == 'schedule'
    steps:
      - run: terraform plan -detailed-exitcode -lock=false || curl -X POST $SLACK_WEBHOOK -d '{"text":"Terraform drift detected in prod"}'$escape$,
  $escape$bash$escape$,
